import logging
from src.auth import authenticate
from src.db import query

logger = logging.getLogger(__name__)

class Server:
    def __init__(self, port: int):
        self.port = port

    def start(self):
        logger.info('Starting server on port %d', self.port)

    def handle_request(self, method: str, path: str, headers: dict):
        logger.debug('Request: %s %s', method, path)
        try:
            user = authenticate(headers.get('Authorization', ''))
            result = query(f'SELECT * FROM {path}')
            return {'status': 200, 'data': result}
        except Exception as e:
            logger.error('Request failed: %s', e)
            return {'status': 500, 'error': str(e)}

import logging

logger = logging.getLogger(__name__)

class AuthError(Exception):
    pass

def authenticate(token: str):
    if not token:
        raise AuthError('No token provided')
    logger.debug('Checking token: %s...', token[:8])
    if token.startswith('valid_'):
        user_id = token.split('_')[1]
        logger.info('User %s authenticated', user_id)
        return user_id
    else:
        logger.error('Auth failed: invalid token')
        raise AuthError('Invalid token')

import logging

logger = logging.getLogger(__name__)

class DBError(Exception):
    pass

def query(sql: str):
    logger.debug('Query: %s', sql)
    if 'DROP' in sql.upper():
        logger.error('Dangerous query blocked: %s', sql)
        raise DBError('Dangerous query blocked')
    return [{'id': 1}]  # mock
